from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a readable sentence from one or more astronaut‑related triples."""
    if not triples:
        return ""
    clauses: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        # Simple handcrafted phrasing for common astronaut predicates
        if p == "birthDate":
            clause = f"{s} was born on {o}"
        elif p == "birthPlace":
            clause = f"{s} was born in {o}"
        elif p == "nationality":
            clause = f"{s} was a {o} astronaut"
        elif p == "occupation":
            clause = f"{s} worked as a {o}"
        elif p == "mission":
            clause = f"{s} participated in the {o} mission"
        elif p == "timeInSpace":
            clause = f"{s} spent {o} minutes in space"
        elif p == "dateOfRetirement":
            clause = f"{s} retired in {o}"
        elif p == "status":
            clause = f"{s} is {o}"
        elif p == "deathDate":
            clause = f"{s} died on {o}"
        elif p == "deathPlace":
            clause = f"{s} died in {o}"
        elif p == "selectedByNasa":
            clause = f"{s} was selected by NASA in {o}"
        elif p == "title":
            clause = f"{s} held the title of {o}"
        elif p == "award":
            clause = f"{s} received the {o}"
        elif p == "ribbonAward":
            clause = f"{s} was awarded the {o}"
        elif p == "commander":
            clause = f"{s} was the commander of {o}"
        elif p == "backupPilot":
            clause = f"{s} served as backup pilot for {o}"
        elif p == "crewMembers":
            clause = f"{s} had crew member {o}"
        else:
            clause = f"{s} {p} {o}"
        clauses.append(clause)
    # Join clauses into a single fluent sentence
    if len(clauses) == 1:
        return clauses[0] + "."
    else:
        return "; ".join(clauses) + "."

# EVOLVE-BLOCK-END

